&lt;%* const title = await tp.system.prompt(&ldquo;文章標題&rdquo;); const slug = title .toLowerCase() .replace(/[^\w\s-]/g, &ldquo;&rdquo;) .replace(/\s+/g, &ldquo;-&rdquo;);
const tags = await tp.system.prompt(&ldquo;標籤（用逗號分隔）&rdquo;, &ldquo;筆記&rdquo;); const category = await tp.system.prompt(&ldquo;分類&rdquo;, &ldquo;技術&rdquo;); const desc = await tp.system.prompt(&ldquo;SEO 描述&rdquo;);
const now = tp.date.now(&ldquo;YYYY-MM-DDTHH:mm:ssZ&rdquo;); %&gt;# title: &ldquo;&lt;%= title %&gt;&rdquo; date: &lt;%= now %&gt; lastmod: &lt;%= now %&gt; draft: false slug: &ldquo;&lt;%= slug %&gt;&rdquo; description: &ldquo;&lt;%= desc %&gt;&rdquo; tags: [&lt;%= tags.split(&quot;,&quot;).map(t =&gt; &quot;${t.trim()}&quot;).join(&quot;, &ldquo;) %&gt;] categories: [&quot;&lt;%= category %&gt;&rdquo;] keywords: [&lt;%= tags.split(&quot;,&quot;).map(t =&gt; &quot;${t.trim()}&quot;).join(&quot;, &ldquo;) %&gt;] author: &ldquo;你的名字&rdquo;# &lt;%= title %&gt;# 寫你的內容&hellip;
